import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.esapi.ESAPI;

public class XSSSecureCode {
    public static void main(String[] args) throws IOException {
        // Simulated user input
        String userInput = "<script>alert('XSS Vulnerability');</script>";

        // Properly encoding user input to prevent XSS
        String encodedUserInput = ESAPI.encoder().encodeForHTML(userInput);

        // Writing encoded output to the webpage
        PrintWriter out = new PrintWriter("output.html");
        out.println("<html>");
        out.println("<head><title>XSS Secure Page</title></head>");
        out.println("<body>");
        out.println("<h1>Welcome to our website!</h1>");
        out.println("<p>Your input: " + encodedUserInput + "</p>"); // Safe output
        out.println("</body>");
        out.println("</html>");

        out.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
